            int v = (int) edge[1];
            long start = edge[2];
            long end = edge[3];
            graph.get(u).add(new Edge(v, start, end));
        }

        PriorityQueue<State> pq = new PriorityQueue<>(Comparator.comparingLong(s -> s.time));
        long[] dist = new long[numNodes];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[0] = 0;
        pq.offer(new State(0, 0));

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int u = current.node;
            long time = current.time;
            if (u == numNodes - 1) {
                return time;
            }
