import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        int nodeCount = (int) n;
        if (nodeCount == 1) return 0;

        // Build adjacency list: node -> list of edges (u, v, start, end)
        Map<Integer, List<long[]>> graph = new HashMap<>();
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long start = edge[2];
            long end = edge[3];
            graph.computeIfAbsent(u, k -> new ArrayList<>()).add(new long[]{v, start, end});
        }

        // Priority queue: (current time, node)
        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.offer(new long[]{0, 0});

        // Visited time for each node
        long[] visitedTime = new long[nodeCount];
        Arrays.fill(visitedTime, Long.MAX_VALUE);
        visitedTime[0] = 0;

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long time = current[0];
            int node = (int) current[1];

            if (node == nodeCount - 1) {
                return time;
            }

            if (time > visitedTime[node]) {
                continue;
            }

            if (!graph.containsKey(node)) {
                continue;
            }

            for (long[] edge : graph.get(node)) {
                int nextNode = (int) edge[0];
                long start = edge[1];
                long end = edge[2];

                // The earliest time we can take this edge is max(time, start)
                long departureTime = Math.max(time, start);
                if (departureTime > end) {
                    continue; // Edge is no longer available
                }

                long arrivalTime = departureTime + 1;
                if (arrivalTime < visitedTime[nextNode]) {
                    visitedTime[nextNode] = arrivalTime;
                    pq.offer(new long[]{arrivalTime, nextNode});
                }
            }
        }

        return -1;
    }
}
