            int u = (int) current[0];
            long arrivalTime = current[1];

            if (u == numNodes - 1) {
                return arrivalTime;
            }

            if (arrivalTime > dist[u]) {
                continue;
            }

            if (!graph.containsKey(u)) {
                continue;
            }

            for (int[] edge : graph.get(u)) {
                int v = edge[0];
                int start = edge[1];
                int end = edge[2];

                // The earliest time we can take this edge is max(arrivalTime, start)
                long departureTime = Math.max(arrivalTime, start);
                if (departureTime > end) {
                    continue; // Edge is no longer available
                }

                long newArrivalTime = departureTime + 1;
                if (newArrivalTime < dist[v]) {
                    dist[v] = newArrivalTime;
                    pq.offer(new long[]{v, newArrivalTime});
