            long start = edge[2];
            long end = edge[3];
            graph.computeIfAbsent(u, k -> new ArrayList<>()).add(new Edge(v, start, end));
        }

        PriorityQueue<State> pq = new PriorityQueue<>(Comparator.comparingLong(s -> s.time));
        pq.offer(new State(0, 0));
        Map<Integer, Long> visited = new HashMap<>();

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int node = current.node;
            long time = current.time;

            if (node == numNodes - 1) {
                return time;
            }

            if (visited.containsKey(node) && visited.get(node) <= time) {
                continue;
            }
            visited.put(node, time);

            // Option to stay (wait) for 1 unit of time
            if (!visited.containsKey(node) || visited.get(node) > time + 1) {
                pq.offer(new State(node, time + 1));
            }

            // Check all outgoing edges
            if (graph.containsKey(node)) {
                for (Edge edge : graph.get(node)) {
                    if (edge.start <= time && time <= edge.end) {
                        int nextNode = edge.to;
                        long arrivalTime = time + 1;
                        if (!visited.containsKey(nextNode) || visited.get(nextNode) > arrivalTime) {
                            pq.offer(new State(nextNode, arrivalTime));
                        }
                    } else if (time < edge.start) {
                        // Wait until edge.start and then take the edge
                        long waitTime = edge.start;
                        long arrivalTime = waitTime + 1;
                        if (!visited.containsKey(edge.to) || visited.get(edge.to) > arrivalTime) {
                            pq.offer(new State(edge.to, arrivalTime));
                        }
                    }
                }
            }
        }

        return -1;
    }

    static class Edge {
        int to;
        long start;
        long end;

        Edge(int to, long start, long end) {
            this.to = to;
            this.start = start;
            this.end = end;
        }
    }

    static class State {
        int node;
        long time;

        State(int node, long time) {
            this.node = node;
            this.time = time;
        }
    }
