public class Solution {
    public static long solve(long n, long[][] edges) {
        // Convert n to int since nodes are 0-based and up to n-1
        int numNodes = (int) n;
        if (numNodes == 1) return 0; // already at node 0 (n-1=0)

        // Build adjacency list: each node has a list of edges (u, v, start, end)
        List<List<long[]>> adj = new ArrayList<>();
        for (int i = 0; i < numNodes; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long start = edge[2];
            long end = edge[3];
            adj.get(u).add(new long[]{v, start, end});
        }

        // Priority queue for Dijkstra's algorithm: (currentTime, node)
        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.offer(new long[]{0, 0}); // start at node 0 at time 0

        // Track the earliest arrival time at each node
        long[] earliestTime = new long[numNodes];
        Arrays.fill(earliestTime, Long.MAX_VALUE);
        earliestTime[0] = 0;

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long currentTime = current[0];
            int u = (int) current[1];

            if (u == numNodes - 1) {
                return currentTime;
            }

            if (currentTime > earliestTime[u]) {
                continue; // already found a better path
            }

            // Option 1: stay at current node (time increases by 1)
            if (currentTime + 1 < earliestTime[u]) {
                earliestTime[u] = currentTime + 1;
                pq.offer(new long[]{currentTime + 1, u});
            }

            // Option 2: take an outgoing edge if possible
            for (long[] edge : adj.get(u)) {
                int v = (int) edge[0];
                long start = edge[1];
                long end = edge[2];

                // The earliest we can take this edge is max(currentTime, start)
                long departureTime = Math.max(currentTime, start);
                if (departureTime <= end) {
                    long arrivalTime = departureTime + 1;
                    if (arrivalTime < earliestTime[v]) {
                        earliestTime[v] = arrivalTime;
                        pq.offer(new long[]{arrivalTime, v});
                    }
                }
            }
        }

        return earliestTime[numNodes - 1] == Long.MAX_VALUE ? -1 : earliestTime[numNodes - 1];
    }
}
