    // Build adjacency list
    Map<Long, List<long[]>> graph = new HashMap<>();
    for (long[] edge : edges) {
        long u = edge[0];
        long v = edge[1];
        long start = edge[2];
        long end = edge[3];
        graph.computeIfAbsent(u, k -> new ArrayList<>()).add(new long[]{v, start, end});
    }

    // Priority queue for Dijkstra's algorithm: [current_time, node]
    PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
    pq.offer(new long[]{0, 0});

    // Visited map to keep track of the earliest time we've seen each node
    Map<Long, Long> visited = new HashMap<>();
    visited.put(0L, 0L);

    while (!pq.isEmpty()) {
        long[] current = pq.poll();
        long currentTime = current[0];
        long currentNode = current[1];

        if (currentNode == n - 1) {
            return currentTime;
        }

        if (currentTime > visited.getOrDefault(currentNode, Long.MAX_VALUE)) {
            continue;
        }

        // Option 1: Stay at current node (move time forward by 1)
        long nextTime = currentTime + 1;
        if (!visited.containsKey(currentNode) || nextTime < visited.getOrDefault(currentNode, Long.MAX_VALUE)) {
            visited.put(currentNode, nextTime);
            pq.offer(new long[]{nextTime, currentNode});
        }

        // Option 2: Move through available edges
        if (graph.containsKey(currentNode)) {
            for (long[] edge : graph.get(currentNode)) {
                long v = edge[0];
                long start = edge[1];
                long end = edge[2];

                if (currentTime > end) {
                    continue; // Edge is no longer available
                }

                long departureTime = Math.max(currentTime, start);
                long arrivalTime = departureTime + 1;

                if (!visited.containsKey(v) || arrivalTime < visited.getOrDefault(v, Long.MAX_VALUE)) {
                    visited.put(v, arrivalTime);
                    pq.offer(new long[]{arrivalTime, v});
                }
