import java.util.*;

public static long solve(long n, long[][] edges) {
    if (n == 1) return 0;

    // Build adjacency list: node -> list of edges (u, v, start, end)
    Map<Long, List<long[]>> graph = new HashMap<>();
    for (long[] edge : edges) {
        long u = edge[0];
        long v = edge[1];
        long start = edge[2];
        long end = edge[3];
        graph.putIfAbsent(u, new ArrayList<>());
        graph.get(u).add(new long[]{v, start, end});
    }

    // Priority queue: (current_time, node)
    PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
    pq.offer(new long[]{0, 0});

    // Visited time for nodes: node -> earliest arrival time
    Map<Long, Long> visited = new HashMap<>();
    visited.put(0L, 0L);

    while (!pq.isEmpty()) {
        long[] current = pq.poll();
        long time = current[0];
        long node = current[1];

        if (node == n - 1) {
            return time;
        }

        if (!graph.containsKey(node)) {
            continue; // no outgoing edges
        }

        for (long[] edge : graph.get(node)) {
            long v = edge[0];
            long start = edge[1];
            long end = edge[2];

            long earliestDeparture = Math.max(time, start);
            if (earliestDeparture > end) {
                continue; // cannot take this edge
            }

            long arrivalTime = earliestDeparture + 1;
            if (!visited.containsKey(v) || arrivalTime < visited.get(v)) {
                visited.put(v, arrivalTime);
                pq.offer(new long[]{arrivalTime, v});
            }
        }
    }

    return -1;
}
