public class Solution {
    public static long solve(long n, long[][] edges) {
        int numNodes = (int) n;
        List<List<Edge>> graph = new ArrayList<>();
        for (int i = 0; i < numNodes; i++) {
            graph.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long start = edge[2];
            long end = edge[3];
            graph.get(u).add(new Edge(v, start, end));
        }

        PriorityQueue<State> pq = new PriorityQueue<>(Comparator.comparingLong(s -> s.time));
        long[] dist = new long[numNodes];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[0] = 0;
        pq.offer(new State(0, 0));

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int u = current.node;
            long time = current.time;
            if (u == numNodes - 1) {
                return time;
            }
            if (time > dist[u]) {
                continue;
            }
            for (Edge edge : graph.get(u)) {
                int v = edge.to;
                long start = edge.start;
                long end = edge.end;
                long arrivalTime;
                if (time <= start) {
                    arrivalTime = start + 1;
                } else if (time <= end) {
                    arrivalTime = time + 1;
                } else {
                    continue;
                }
                if (arrivalTime < dist[v]) {
                    dist[v] = arrivalTime;
                    pq.offer(new State(v, arrivalTime));
                }
            }
            // Option to wait (move to next time)
            long nextTime = time + 1;
            if (nextTime < dist[u]) {
                dist[u] = nextTime;
                pq.offer(new State(u, nextTime));
            }
        }
        return -1;
    }

    static class Edge {
        int to;
        long start;
        long end;

        Edge(int to, long start, long end) {
            this.to = to;
            this.start = start;
            this.end = end;
        }
    }

    static class State {
        int node;
        long time;

        State(int node, long time) {
            this.node = node;
            this.time = time;
        }
    }
}
